// MARK: - Models.swift

import Foundation
import CoreLocation

struct ServiceLocation: Identifiable {
    let id: String
    let name: String
    let description: String
    let coordinate: CLLocationCoordinate2D
    let category: ServiceCategory
    let rating: Double
    let priceRange: String
    let imageURL: String?
    let isAvailable: Bool
    
    enum ServiceCategory: String, CaseIterable {
        case restaurant = "Restaurant"
        case parking = "Parking"
        case charging = "EV Charging"
        case service = "Service"
        
        var icon: String {
            switch self {
            case .restaurant: return "fork.knife"
            case .parking: return "p.circle.fill"
            case .charging: return "bolt.car.fill"
            case .service: return "wrench.and.screwdriver.fill"
            }
        }
        
        var color: UIColor {
            switch self {
            case .restaurant: return .systemOrange
            case .parking: return .systemBlue
            case .charging: return .systemGreen
            case .service: return .systemPurple
            }
        }
    }
}

struct Booking: Identifiable {
    let id: String
    let location: ServiceLocation
    let date: Date
    let status: BookingStatus
    let totalAmount: Double
    
    enum BookingStatus: String {
        case confirmed = "Confirmed"
        case pending = "Pending"
        case completed = "Completed"
        case cancelled = "Cancelled"
        
        var color: UIColor {
            switch self {
            case .confirmed: return .systemGreen
            case .pending: return .systemOrange
            case .completed: return .systemBlue
            case .cancelled: return .systemRed
            }
        }
    }
}

struct PaymentIntentResponse: Codable {
    let clientSecret: String
    let ephemeralKey: String
    let customerId: String
    let publishableKey: String
}


